{"code": "import yfinance as yf
import json

symbols = ['AAPL', 'NVDA', 'META', 'GOOGL', 'MSFT', 'TSLA']
results = {}

for sym in symbols:
    try:
        t = yf.Ticker(sym)
        info = t.info

        price = info.get('regularMarketPrice') or info.get('currentPrice') or info.get('navPrice')
        trailing_pe = info.get('trailingPE')
        forward_pe = info.get('forwardPE')
        peg_ratio = info.get('pegRatio')

        results[sym] = {
            'price': round(price, 2) if price else None,
            'trailingPE': round(trailing_pe, 2) if trailing_pe else None,
            'forwardPE': round(forward_pe, 2) if forward_pe else None,
            'pegRatio': round(peg_ratio, 2) if peg_ratio else None,
            'marketCap': info.get('marketCap'),
            'volume': info.get('averageVolume'),
            'divYield': info.get('dividendYield'),
            'profitMargins': info.get('profitMargins'),
            'revenueGrowth': info.get('revenueGrowth'),
            'earningsGrowth': info.get('earningsGrowth'),
        }
    except Exception as e:
        results[sym] = {'error': str(e)}

# Print for inspection
for sym, data in results.items():
    print(f"\n=== {sym} ===")
    for k, v in data.items():
        print(f"  {k}: {v}")"}

